#   lat &lt;- as.numeric(m[2]) + as.numeric(m[3]) / 60 + as.numeric(m[4]) / 3600
#   if (m[5] == "S") lat &lt;- -lat
#   lon &lt;- as.numeric(m[6]) + as.numeric(m[7]) / 60 + as.numeric(m[8]) / 3600
